#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelLayerNormCustom {
public:
    __aicore__ inline KernelLayerNormCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias,
                                uint32_t rows, uint32_t cols, uint32_t tileLen, float eps)
    {
        rows_ = rows;
        cols_ = cols;
        tileLen_ = tileLen;
        eps_ = eps;

        xGm_.SetGlobalBuffer((__gm__ float*)x, rows_ * cols_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, rows_ * cols_);
        weightGm_.SetGlobalBuffer((__gm__ float*)weight, cols_);
        biasGm_.SetGlobalBuffer((__gm__ float*)bias, cols_);

        // We need multiple local tensors: xLocal, weightLocal, biasLocal, yLocal, and a temporary for subtract/scale.
        // Budget: 5 tiles (2 for pass1? Actually we reuse; worst-case 4 tiles simultaneously)
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueW_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(inQueueB_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (rows_ == 0 || cols_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Each block processes rows in a grid-stride loop
        for (uint32_t row = blockIdx; row < rows_; row += blockNum) {
            ProcessRow(row);
        }
    }

private:
    __aicore__ inline void ProcessRow(uint32_t row)
    {
        // First pass: compute mean and variance for this row
        float sum = 0.0f;
        float sumSq = 0.0f;
        uint32_t offset = row * cols_;

        uint32_t remaining = cols_;
        uint32_t base = 0;
        while (remaining > 0) {
            uint32_t len = (remaining > tileLen_) ? tileLen_ : remaining;
            // Load x tile
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset + base], len);
            inQueueX_.EnQue(xLocal);

            AscendC::LocalTensor<float> xDeq = inQueueX_.DeQue<float>();
            // Compute sum and sumSq using AscendC reductions or manual loop? Use ReduceSum
            // AscendC::ReduceSum sum
            float tileSum = AscendC::ReduceSum(xDeq, len);
            // For sumSq, we need element-wise square and then reduce
            AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
            AscendC::Mul(tmp, xDeq, xDeq, len);
            float tileSumSq = AscendC::ReduceSum(tmp, len);
            tmpQueue_.FreeTensor(tmp);
            sum += tileSum;
            sumSq += tileSumSq;

            inQueueX_.FreeTensor(xDeq);

            base += len;
            remaining -= len;
        }

        float mean = sum / static_cast<float>(cols_);
        float var = sumSq / static_cast<float>(cols_) - mean * mean;
        float invStd = 1.0f / sqrtf(var + eps_);

        // Second pass: normalize and apply weight and bias
        remaining = cols_;
        base = 0;
        while (remaining > 0) {
            uint32_t len = (remaining > tileLen_) ? tileLen_ : remaining;

            // Load x
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset + base], len);
            inQueueX_.EnQue(xLocal);

            // Load weight and bias (constant across rows, can be cached but we reload each row for simplicity)
            AscendC::LocalTensor<float> wLocal = inQueueW_.AllocTensor<float>();
            AscendC::DataCopy(wLocal, weightGm_[base], len);
            inQueueW_.EnQue(wLocal);

            AscendC::LocalTensor<float> bLocal = inQueueB_.AllocTensor<float>();
            AscendC::DataCopy(bLocal, biasGm_[base], len);
            inQueueB_.EnQue(bLocal);

            // Dequeue
            AscendC::LocalTensor<float> xDeq = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> wDeq = inQueueW_.DeQue<float>();
            AscendC::LocalTensor<float> bDeq = inQueueB_.DeQue<float>();

            // y = (x - mean) * invStd * weight + bias
            AscendC::LocalTensor<float> tmp = tmpQueue_.AllocTensor<float>();
            AscendC::Subs(tmp, xDeq, mean, len);
            AscendC::Muls(tmp, tmp, invStd, len);
            AscendC::Mul(tmp, tmp, wDeq, len);
            AscendC::Add(tmp, tmp, bDeq, len);

            // Write to y
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::DataCopy(yLocal, tmp, len); // copy from tmp to yLocal (or use tmp as yLocal directly, but we need to enqueue)
            outQueueY_.EnQue(yLocal);

            // Free
            tmpQueue_.FreeTensor(tmp);
            inQueueX_.FreeTensor(xDeq);
            inQueueW_.FreeTensor(wDeq);
            inQueueB_.FreeTensor(bDeq);

            // Dequeue y and write to global
            AscendC::LocalTensor<float> yDeq = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[offset + base], yDeq, len);
            outQueueY_.FreeTensor(yDeq);

            base += len;
            remaining -= len;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueW_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueB_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    AscendC::GlobalTensor<float> weightGm_;
    AscendC::GlobalTensor<float> biasGm_;

    uint32_t rows_ {0};
    uint32_t cols_ {0};
    uint32_t tileLen_ {0};
    float eps_ {1e-5f};
};

extern "C" __global__ __aicore__ void layer_norm_custom(GM_ADDR x, GM_ADDR y, GM_ADDR weight, GM_ADDR bias, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLayerNormCustom op;
    op.Init(x, y, weight, bias, tiling_data.rows, tiling_data.cols, tiling_data.tileLen, tiling_data.eps);
    op.Process();
}
