import torch
import torch_npu
import custom_ops_lib

_FN = 'layer_norm_custom'

class ModelNew(torch.nn.Module):
    def __init__(self, normalized_shape):
        super(ModelNew, self).__init__()
        # We need to mirror the LayerNorm parameters
        self.normalized_shape = normalized_shape
        self.weight = torch.nn.Parameter(torch.ones(normalized_shape, dtype=torch.float32))
        self.bias = torch.nn.Parameter(torch.zeros(normalized_shape, dtype=torch.float32))
        self.eps = 1e-5

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Flatten weight and bias to 1D: they already have shape normalized_shape (3D: features, dim1, dim2)
        w = self.weight.view(-1)
        b = self.bias.view(-1)
        fn = getattr(custom_ops_lib, _FN)
        # The custom kernel expects all inputs as Tensors; eps can be passed as a float attribute in the operator,
        # but our custom op uses attribute "eps". In this binding, we assume the kernel receives eps via tiling.
        # So we just pass x, w, b.
        return fn(x, w, b)
